def get_stocks_for_provider(suffix='.NS'):
    """Get stocks with appropriate suffix for provider (NS for Yahoo, BSE for Alpha Vantage)"""
    return [
        {
            'symbol': f"{s['symbol']}{suffix}",
            'name': s['name'],
            'isin': s['isin']
        }
        for s in INDIAN_STOCKS
    ]
